console.log("🧟 Scaffolding the Config Graveyard...");

// Ensure .circleci exists
const circleCiDir = path.join(PROJECT_ROOT, '.circleci');
if (!fs.existsSync(circleCiDir)) {
    fs.mkdirSync(circleCiDir);
}

for (const [filename, content] of Object.entries(filesToCreate)) {
    const filePath = path.join(PROJECT_ROOT, filename);
    fs.writeFileSync(filePath, content);
    console.log(`Created ${filename}`);
}

console.log("✅ Config Graveyard generation complete!");
